from flask import Flask, request
from prometheus_client import Counter, generate_latest, REGISTRY

app = Flask(__name__)

# Create a dictionary to store counters for each user-path combination
user_path_counters = {}

@app.route('/metrics')
def metrics():
    return generate_latest(REGISTRY)

@app.before_request
def track_request():
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    full_path = request.full_path

    # Create a unique key for each user-path combination
    user_path_key = f"{user_id}-{full_path}"

    # If the counter for this user-path combination doesn't exist, create it
    if user_path_key not in user_path_counters:
        user_path_counters[user_path_key] = Counter(
            f"http_requests_{user_id}_{hash(full_path)}",
            'HTTP requests tracked by user and path',
            ['user_id', 'session_id', 'full_path']
        )

    # Increment the counter for this request
    user_path_counters[user_path_key].labels(user_id=user_id, session_id=session_id, full_path=full_path).inc()

@app.route('/')
def index():
    return "Hello, World!"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)